<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">            roll_keep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 保留最近 7 天日志</span></span>
